use std::path::PathBuf;

use crate::keybindings::Keybindings;

/// Current config format version. Increment when breaking changes are introduced.
pub const CONFIG_VERSION: u64 = 1;

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Config {
    #[serde(default)]
    pub theme: String,
    #[serde(default = "default_show_hidden")]
    pub show_hidden: bool,
    #[serde(default = "default_preview")]
    pub preview: PreviewConfig,
    #[serde(default = "default_shell")]
    pub shell: ShellConfig,
    #[serde(default)]
    pub keybindings: Keybindings,
    #[serde(default = "default_plugins")]
    pub plugins: PluginConfig,
    /// Config format version for migration support.
    #[serde(default = "default_config_version")]
    pub config_version: u64,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PreviewConfig {
    #[serde(default = "default_true")]
    pub syntax_highlight: bool,
    #[serde(default = "default_true")]
    pub image_preview: bool,
    #[serde(default = "default_max_lines")]
    pub max_lines: usize,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ShellConfig {
    #[serde(default = "default_true")]
    pub cd_on_quit: bool,
    #[serde(default = "default_shell_command")]
    pub shell_command: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PluginConfig {
    #[serde(default = "default_true")]
    pub enabled: bool,
    #[serde(default)]
    pub auto_load: bool,
}

fn default_show_hidden() -> bool { false }
fn default_true() -> bool { true }
fn default_max_lines() -> usize { 100 }

fn default_preview() -> PreviewConfig {
    PreviewConfig {
        syntax_highlight: true,
        image_preview: true,
        max_lines: 100,
    }
}

fn default_shell() -> ShellConfig {
    ShellConfig {
        cd_on_quit: true,
        shell_command: default_shell_command(),
    }
}

fn default_shell_command() -> String {
    std::env::var("SHELL").unwrap_or_else(|_| "/bin/sh".to_string())
}

fn default_plugins() -> PluginConfig {
    PluginConfig {
        enabled: true,
        auto_load: true,
    }
}

fn default_config_version() -> u64 {
    CONFIG_VERSION
}

impl Default for Config {
    fn default() -> Self {
        Self {
            theme: "synthwave".to_string(),
            show_hidden: false,
            preview: default_preview(),
            shell: default_shell(),
            keybindings: Keybindings::default(),
            plugins: default_plugins(),
            config_version: CONFIG_VERSION,
        }
    }
}

impl Config {
    pub fn load() -> Self {
        let path = Self::config_path();
        Self::load_from(&path)
    }

    pub fn load_from(path: &std::path::Path) -> Self {
        if path.exists() {
            if let Ok(content) = std::fs::read_to_string(path) {
                if let Ok(config) = toml::from_str::<Config>(&content) {
                    return config;
                }
            }
        }
        Config::default()
    }

    pub fn config_path() -> PathBuf {
        dirs::config_dir()
            .unwrap_or_else(|| PathBuf::from("~/.config"))
            .join("vhs-86")
            .join("config.toml")
    }

    /// Save the current config to the default config path.
    pub fn save(&self) -> std::io::Result<()> {
        self.save_to(&Self::config_path())
    }

    /// Save the current config to a specific path.
    pub fn save_to(&self, path: &std::path::Path) -> std::io::Result<()> {
        if let Some(parent) = path.parent() {
            std::fs::create_dir_all(parent)?;
        }
        let content = toml::to_string_pretty(self)
            .map_err(|e| std::io::Error::new(std::io::ErrorKind::InvalidData, e))?;
        std::fs::write(path, content)
    }

    /// Migrate an older config to the current version.
    /// Returns true if migration was performed.
    pub fn migrate(&mut self) -> bool {
        if self.config_version >= CONFIG_VERSION {
            return false;
        }

        if self.config_version == 0 {
            if self.theme.is_empty() {
                self.theme = "synthwave".to_string();
            }
            self.config_version = CONFIG_VERSION;
            return true;
        }

        self.config_version = CONFIG_VERSION;
        true
    }

    /// Load config with automatic migration.
    pub fn load_and_migrate() -> (Self, bool) {
        let mut config = Self::load();
        let migrated = config.migrate();
        if migrated {
            let _ = config.save();
        }
        (config, migrated)
    }

    /// Load config from path with automatic migration.
    pub fn load_from_and_migrate(path: &std::path::Path) -> (Self, bool) {
        let mut config = Self::load_from(path);
        let migrated = config.migrate();
        if migrated {
            let _ = config.save_to(path);
        }
        (config, migrated)
    }
}

