    #[test]
    fn test_detect_archive_zip() {
        assert_eq!(
            detect_archive(Path::new("file.zip")),
            Some(ArchiveType::Zip)
        );
    }

    #[test]
    fn test_detect_archive_tar() {
        assert_eq!(
            detect_archive(Path::new("file.tar")),
            Some(ArchiveType::Tar)
        );
    }

    #[test]
    fn test_detect_archive_tgz() {
        assert_eq!(
