        );
    }

    #[test]
    fn test_detect_archive_not_archive() {
        assert_eq!(detect_archive(Path::new("file.txt")), None);
        assert_eq!(detect_archive(Path::new("file.pdf")), None);
    }

    #[test]
    fn test_archive_type_name() {
